"use client";

import { useEffect, useMemo, useRef, useState } from "react";

import type { PullStatus, PullToRefreshifyProps } from "./types";
import { Events } from "./utils/events";
import { getScrollTop } from "./utils/getScrollTop";
import { useDrag } from "./utils/useDrag";
import { useScrollParent } from "./utils/useScrollParent";
import { useUnmountedRef } from "./utils/useUnmountedRef";
import { useUpdateEffect } from "./utils/useUpdateEffect";

const visuallyHiddenStyle = {
  position: "absolute",
  width: 1,
  height: 1,
  padding: 0,
  margin: -1,
  overflow: "hidden",
  clip: "rect(0, 0, 0, 0)",
  whiteSpace: "nowrap",
  border: 0,
} as const;

const defaultLiveStatus: Record<PullStatus, string> = {
  normal: "",
  pulling: "Pulling to refresh",
  canRelease: "Release to refresh",
  refreshing: "Refreshing",
  complete: "Refresh complete",
};

export const PullToRefreshify = ({
  className,
  style,
  animationDuration = 300,
  completeDelay = 500,
  refreshing = false,
  headHeight = 50,
  startDistance = 30,
  resistance = 0.6,
  threshold = headHeight,
  onRefresh,
  disabled = false,
  prefixCls = "pull-to-refreshify",
  refreshButtonLabel = "Refresh",
  renderStatus,
  renderText,
  children,
}: PullToRefreshifyProps) => {
  const [pullRef, scrollParentRef] = useScrollParent(!disabled);
  const unmountedRef = useUnmountedRef();
  const completeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const refreshRequestedRef = useRef(refreshing);
  const [reducedMotion, setReducedMotion] = useState(false);
  const [[offsetY, duration, status], setState] = useState<
    [number, number, PullStatus]
  >(
    refreshing
      ? [headHeight, animationDuration, "refreshing"]
      : [0, 0, "normal"]
  );

  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return;

    const media = window.matchMedia("(prefers-reduced-motion: reduce)");
    const update = () => setReducedMotion(media.matches);
    update();
    media.addEventListener("change", update);
    return () => media.removeEventListener("change", update);
  }, []);

  useEffect(
    () => () => {
      if (completeTimerRef.current !== null) {
        clearTimeout(completeTimerRef.current);
      }
    },
    []
  );

  const dispatch = (nextStatus: PullStatus, dragOffsetY = 0) => {
    if (completeTimerRef.current !== null) {
      clearTimeout(completeTimerRef.current);
      completeTimerRef.current = null;
    }

    switch (nextStatus) {
      case "pulling":
      case "canRelease":
        setState([dragOffsetY, 0, nextStatus]);
        break;

      case "refreshing":
        setState([headHeight, animationDuration, nextStatus]);
        break;

      case "complete":
        setState([headHeight, animationDuration, nextStatus]);
        if (unmountedRef.current) return;
        completeTimerRef.current = setTimeout(() => {
          completeTimerRef.current = null;
          if (!unmountedRef.current && !refreshRequestedRef.current) {
            setState([0, animationDuration, "normal"]);
          }
        }, Math.max(0, completeDelay));
        break;

      default:
        setState([0, animationDuration, nextStatus]);
    }
  };

  // Skip the first render
  useUpdateEffect(() => {
    if (refreshing) {
      refreshRequestedRef.current = true;
      dispatch("refreshing");
    } else {
      refreshRequestedRef.current = false;
      dispatch("complete");
    }
  }, [refreshing]);

  const triggerRefresh = () => {
    if (
      disabled ||
      refreshing ||
      refreshRequestedRef.current ||
      (status !== "normal" && status !== "canRelease") ||
      typeof onRefresh !== "function"
    ) {
      return;
    }

    refreshRequestedRef.current = true;
    dispatch("refreshing");
    try {
      onRefresh();
    } catch (error) {
      refreshRequestedRef.current = false;
      dispatch("normal");
      throw error;
    }
  };

  // Handle drag events
  const dragRef = useDrag({
    onDragMove: (event, { offsetX, offsetY: dragOffsetY }) => {
      if (
        // Not set onRefresh event
        !onRefresh ||
        // Pull up or continue a horizontal gesture
        dragOffsetY <= 0 ||
        Math.abs(dragOffsetY) <= Math.abs(offsetX) ||
        // Not scrolled to top
        getScrollTop(scrollParentRef.current) > 0 ||
        // Refreshing state has been triggered
        ["refreshing", "complete"].includes(status) ||
        disabled
      ) {
        return false;
      }

      // Solve the bug that the low-end Android system only triggers the touchmove event once
      if (!Events.isSupportsPassive() && event.cancelable) {
        event.preventDefault();
      }

      const viewportHeight = Math.max(
        typeof window === "undefined" ? 0 : window.innerHeight,
        1
      );
      const ratio = Math.min(dragOffsetY / viewportHeight, 1);
      const offset = Math.max(0, dragOffsetY * (1 - ratio) * resistance);

      // Determine whether the condition for releasing immediate refresh is met
      const action =
        offset - startDistance < threshold ? "pulling" : "canRelease";

      dispatch(action, offset);
      return true;
    },
    onDragEnd: (_, { offsetY: dragOffsetY }) => {
      if (!dragOffsetY) return;

      if (disabled || status !== "canRelease") {
        if (status === "pulling" || status === "canRelease") {
          dispatch("normal");
        }
        return;
      }

      triggerRefresh();
    },
    onDragCancel: () => {
      if (status === "pulling" || status === "canRelease") {
        dispatch("normal");
      }
    },
  });

  let percent = 0;
  if (offsetY >= startDistance) {
    percent =
      threshold > 0
        ? ((offsetY - startDistance < threshold
            ? offsetY - startDistance
            : threshold) *
            100) /
          threshold
        : 100;
  }

  const liveStatus = useMemo(
    () => (renderStatus ? renderStatus(status) : defaultLiveStatus[status]),
    [renderStatus, status]
  );
  const refreshUnavailable = disabled || refreshing || status !== "normal";
  const transitionDuration = reducedMotion ? 0 : duration;

  return (
    <div
      ref={dragRef}
      aria-busy={status === "refreshing"}
      aria-disabled={disabled || undefined}
      className={className ? `${prefixCls} ${className}` : prefixCls}
      style={{
        minHeight: headHeight,
        overflowY: "hidden",
        touchAction: "pan-y",
        ...style,
      }}
    >
      <div
        className={`${prefixCls}__controls`}
        style={{
          display: "flex",
          justifyContent: "flex-end",
          padding: "0.5rem",
        }}
      >
        <button
          type="button"
          className={`${prefixCls}__button`}
          disabled={refreshUnavailable}
          onClick={triggerRefresh}
          style={{
            minHeight: 44,
            padding: "0.625rem 0.875rem",
            border: "1px solid currentColor",
            borderRadius: "0.5rem",
            background: "transparent",
            color: "inherit",
            cursor: refreshUnavailable ? "not-allowed" : "pointer",
            font: "inherit",
            opacity: refreshUnavailable ? 0.55 : 1,
            touchAction: "manipulation",
            whiteSpace: "nowrap",
          }}
        >
          {refreshButtonLabel}
        </button>
      </div>
      <div
        ref={pullRef}
        className={`${prefixCls}__content`}
        style={{
          willChange: "transform",
          WebkitTransition: `transform ${transitionDuration}ms`,
          transition: `transform ${transitionDuration}ms`,
          WebkitTransform: `translate3d(0, ${offsetY}px, 0)`,
          transform: `translate3d(0, ${offsetY}px, 0)`,
        }}
      >
        <div
          key={offsetY.toFixed(0)}
          aria-hidden="true"
          className={`${prefixCls}__refresh`}
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            color: "inherit",
            fontSize: "14px",
            marginTop: -headHeight,
            height: headHeight,
          }}
        >
          {renderText(status, percent)}
        </div>
        <div className={`${prefixCls}__body`}>{children}</div>
      </div>
      <span
        role="status"
        aria-live="polite"
        aria-atomic="true"
        style={visuallyHiddenStyle}
      >
        {liveStatus}
      </span>
    </div>
  );
};

import type { CSSProperties, ReactNode } from "react";

export type PullStatus =
  | "normal"
  | "pulling"
  | "canRelease"
  | "refreshing"
  | "complete";

export interface PullToRefreshifyProps {
  className?: string;
  style?: CSSProperties;
  /**
   * Whether to display the refreshing status
   */
  refreshing?: boolean;
  // Handler function when refresh triggered
  onRefresh: () => void;
  /**
   * The time for the delay to disappear after completion, the unit is ms
   */
  completeDelay?: number;
  /**
   * The time for animation duration, the unit is ms
   */
  animationDuration?: number;
  /**
   * The height of the head prompt content area, the unit is px
   */
  headHeight?: number;
  /**
   * How far to start the pulling status, unit is px
   */
  startDistance?: number;
  /**
   * How far to pull down to trigger refresh, unit is px
   */
  threshold?: number;
  /**
   * Scale of difficulty to pull down
   */
  resistance?: number;
  /**
   * Whether the PullToRefresh is disabled
   */
  disabled?: boolean;
  /**
   * Customize the pulling content according to the pulling status
   */
  renderText: (status: PullStatus, percent: number) => ReactNode;
  /**
   * Customize the concise status announced when the pull state changes
   */
  renderStatus?: (status: PullStatus) => ReactNode;
  /**
   * Customize the visible non-gesture refresh action label
   */
  refreshButtonLabel?: ReactNode;
  /**
   * prefix class
   */
  prefixCls?: string;
  children?: ReactNode;
}

let supportsPassive: boolean | undefined;

const detectPassiveSupport = () => {
  if (supportsPassive !== undefined) return supportsPassive;

  if (typeof window === "undefined") return false;
  supportsPassive = false;

  const listener = () => {};
  try {
    const options = Object.defineProperty({}, "passive", {
      get() {
        supportsPassive = true;
      },
    });
    window.addEventListener("test", listener, options);
    window.removeEventListener("test", listener, options);
  } catch {
    // Passive event options are optional.
  }

  return supportsPassive;
};

export const Events = {
  isSupportsPassive: detectPassiveSupport,
  on(
    el: Element | Window | Document,
    type: string,
    callback: EventListener,
    options: AddEventListenerOptions | boolean = { passive: false }
  ) {
    el.addEventListener(
      type,
      callback,
      detectPassiveSupport() ? options : false
    );
  },

  off(
    el: Element | Window | Document,
    type: string,
    callback: EventListener,
    options: AddEventListenerOptions | boolean = { passive: false }
  ) {
    el.removeEventListener(
      type,
      callback,
      detectPassiveSupport() ? options : false
    );
  },
};

export type ScrollParent = Element | Window;

/**
 * get element scroll top
 */
export const getScrollTop = (ele: ScrollParent | null): number => {
  if (
    !ele ||
    typeof window === "undefined" ||
    typeof document === "undefined"
  ) {
    return 0;
  }

  if (
    ele === window ||
    ele === document.documentElement ||
    ele === document.body ||
    ele === document.scrollingElement
  ) {
    return Math.max(
      0,
      window.scrollY,
      document.documentElement.scrollTop,
      document.body.scrollTop
    );
  }

  return Math.max(0, (ele as Element).scrollTop);
};

import { useEffect, useRef } from "react";

import { Events } from "./events";
import { useLatest } from "./useLatest";

export interface DragState {
  startX: number;
  startY: number;
  offsetX: number;
  offsetY: number;
}

const initialDragState: DragState = {
  startX: 0,
  startY: 0,
  offsetX: 0,
  offsetY: 0,
};

export type DragEvent = globalThis.MouseEvent | TouchEvent;

function isMouseEvent(event: DragEvent): event is globalThis.MouseEvent {
  return !("touches" in event);
}

export const useDrag = ({
  onDragStart,
  onDragMove,
  onDragEnd,
  onDragCancel,
}: {
  onDragStart?: (event: DragEvent, dragState: DragState) => void;
  onDragMove?: (event: DragEvent, dragState: DragState) => boolean;
  onDragEnd?: (event: DragEvent, dragState: DragState) => void;
  onDragCancel?: (event: Event, dragState: DragState) => void;
}) => {
  const ref = useRef<HTMLDivElement | null>(null);
  const onDragStartRef = useLatest(onDragStart);
  const onDragMoveRef = useLatest(onDragMove);
  const onDragEndRef = useLatest(onDragEnd);
  const onDragCancelRef = useLatest(onDragCancel);

  useEffect(() => {
    const dragEl = ref.current;

    if (!dragEl || typeof window === "undefined") return;

    let dragState: DragState = { ...initialDragState };
    let isStart = false;

    const initDragState = () => {
      dragState = { ...initialDragState };
    };

    const handleDragStart = ((event: DragEvent) => {
      if (isMouseEvent(event)) {
        if (event.button !== 0) return;
      } else if (event.touches.length !== 1) {
        return;
      }

      isStart = true;
      initDragState();
      if (isMouseEvent(event)) {
        dragState.startX = event.clientX;
        dragState.startY = event.clientY;
      } else {
        const [touch] = event.touches;
        dragState.startX = touch.pageX;
        dragState.startY = touch.pageY;
      }
      onDragStartRef.current?.(event, dragState);
    }) as EventListener;

    const handleDragMove = ((event: DragEvent) => {
      if (!isStart) return;

      let currentX = 0;
      let currentY = 0;

      if (isMouseEvent(event)) {
        currentX = event.clientX;
        currentY = event.clientY;
      } else {
        const [touch] = event.touches;
        if (!touch) return;
        currentX = touch.pageX;
        currentY = touch.pageY;
      }

      const state = {
        ...dragState,
        offsetX: currentX - dragState.startX,
        offsetY: currentY - dragState.startY,
      };

      if (onDragMoveRef.current?.(event, state)) {
        dragState = state;
      }
    }) as EventListener;

    const handleDragEnd = ((event: DragEvent) => {
      if (!isStart) return;
      isStart = false;
      onDragEndRef.current?.(event, dragState);
      initDragState();
    }) as EventListener;

    const handleDragCancel = ((event: Event) => {
      if (!isStart) return;
      isStart = false;
      onDragCancelRef.current?.(event, dragState);
      initDragState();
    }) as EventListener;

    const handleVisibilityChange = () => {
      if (document.visibilityState === "hidden") {
        handleDragCancel(new Event("visibilitychange"));
      }
    };

    Events.on(dragEl, "touchstart", handleDragStart);
    Events.on(dragEl, "touchmove", handleDragMove);
    Events.on(dragEl, "touchend", handleDragEnd);
    Events.on(dragEl, "touchcancel", handleDragCancel);
    Events.on(dragEl, "mousedown", handleDragStart);
    Events.on(window, "mousemove", handleDragMove);
    Events.on(window, "mouseup", handleDragEnd);
    Events.on(window, "pointercancel", handleDragCancel);
    Events.on(window, "blur", handleDragCancel);
    Events.on(document, "visibilitychange", handleVisibilityChange);

    return () => {
      Events.off(dragEl, "touchstart", handleDragStart);
      Events.off(dragEl, "touchmove", handleDragMove);
      Events.off(dragEl, "touchend", handleDragEnd);
      Events.off(dragEl, "touchcancel", handleDragCancel);
      Events.off(dragEl, "mousedown", handleDragStart);
      Events.off(window, "mousemove", handleDragMove);
      Events.off(window, "mouseup", handleDragEnd);
      Events.off(window, "pointercancel", handleDragCancel);
      Events.off(window, "blur", handleDragCancel);
      Events.off(document, "visibilitychange", handleVisibilityChange);
    };
  }, [onDragCancelRef, onDragEndRef, onDragMoveRef, onDragStartRef]);

  return ref;
};

import { useRef } from "react";

export const useFirstMountState = (): boolean => {
  const isFirst = useRef(true);

  if (isFirst.current) {
    isFirst.current = false;

    return true;
  }

  return isFirst.current;
};

import { useRef } from "react";

export const useLatest = <T>(value: T): { readonly current: T } => {
  const ref = useRef(value);
  ref.current = value;
  return ref;
};

import { useEffect, useRef } from "react";

import { Events } from "./events";
import { getScrollTop } from "./getScrollTop";
import type { ScrollParent } from "./getScrollTop";

const getScrollParent = (node: Element | null): ScrollParent | null => {
  if (
    !node ||
    typeof window === "undefined" ||
    typeof document === "undefined"
  ) {
    return null;
  }

  let current: Element | null = node;
  while (
    current &&
    current !== document.body &&
    current !== document.documentElement
  ) {
    const computedStyle = window.getComputedStyle(current);
    const canScroll = [computedStyle.overflowY, computedStyle.overflow].some(
      (value) => ["scroll", "auto", "overlay"].includes(value)
    );

    if (canScroll && current.scrollHeight > current.clientHeight) {
      return current;
    }
    current = current.parentElement;
  }

  return window;
};

export const useScrollParent = (enabled = true) => {
  const pullRef = useRef<HTMLDivElement | null>(null);
  const scrollParentRef = useRef<ScrollParent | null>(null);

  useEffect(() => {
    if (typeof window === "undefined" || typeof document === "undefined") {
      return;
    }

    let touchStartX: number | null = null;
    let touchStartY: number | null = null;
    let observedParent: Element | null = null;
    let unbindScrollParentEvents = () => {};

    const bindScrollParentEvents = (scrollParent: ScrollParent) => {
      const handleTouchstart = ((event: TouchEvent) => {
        const [touch] = event.touches;
        if (!touch) return;
        touchStartX = touch.pageX;
        touchStartY = touch.pageY;
      }) as EventListener;

      const handleTouchmove = ((event: TouchEvent) => {
        const [touch] = event.touches;
        if (!touch || touchStartX === null || touchStartY === null) return;

        const deltaX = touch.pageX - touchStartX;
        const deltaY = touch.pageY - touchStartY;
        if (
          deltaY > 0 &&
          Math.abs(deltaY) > Math.abs(deltaX) &&
          event.cancelable &&
          getScrollTop(scrollParent) === 0 &&
          event.target &&
          pullRef.current?.contains(event.target as Node)
        ) {
          event.preventDefault();
        }
      }) as EventListener;

      const handleTouchend = (() => {
        touchStartX = null;
        touchStartY = null;
      }) as EventListener;

      Events.on(scrollParent, "touchstart", handleTouchstart);
      Events.on(scrollParent, "touchmove", handleTouchmove);
      Events.on(scrollParent, "touchend", handleTouchend);
      Events.on(scrollParent, "touchcancel", handleTouchend);

      return () => {
        Events.off(scrollParent, "touchstart", handleTouchstart);
        Events.off(scrollParent, "touchmove", handleTouchmove);
        Events.off(scrollParent, "touchend", handleTouchend);
        Events.off(scrollParent, "touchcancel", handleTouchend);
      };
    };

    let resizeObserver: ResizeObserver | null = null;
    const updateScrollParent = () => {
      const nextScrollParent = getScrollParent(pullRef.current);
      if (nextScrollParent === scrollParentRef.current) return;

      unbindScrollParentEvents();
      unbindScrollParentEvents = () => {};
      scrollParentRef.current = nextScrollParent;

      if (resizeObserver && observedParent) {
        resizeObserver.unobserve(observedParent);
      }
      observedParent = nextScrollParent instanceof Element ? nextScrollParent : null;
      if (resizeObserver && observedParent) {
        resizeObserver.observe(observedParent);
      }

      if (enabled && nextScrollParent) {
        unbindScrollParentEvents = bindScrollParentEvents(nextScrollParent);
      }
    };

    if (typeof ResizeObserver !== "undefined") {
      resizeObserver = new ResizeObserver(updateScrollParent);
      if (pullRef.current) resizeObserver.observe(pullRef.current);
    }

    updateScrollParent();
    window.addEventListener("resize", updateScrollParent);
    window.addEventListener("orientationchange", updateScrollParent);

    return () => {
      unbindScrollParentEvents();
      resizeObserver?.disconnect();
      window.removeEventListener("resize", updateScrollParent);
      window.removeEventListener("orientationchange", updateScrollParent);
      scrollParentRef.current = null;
    };
  }, [enabled]);

  return [pullRef, scrollParentRef] as const;
};

import { useRef, useEffect } from "react";

export const useUnmountedRef = () => {
  const unmountedRef = useRef(false);
  useEffect(() => {
    unmountedRef.current = false;

    return () => {
      unmountedRef.current = true;
    };
  }, []);
  return unmountedRef;
};

import { useEffect } from "react";
import { useFirstMountState } from "./useFirstMountState";

export const useUpdateEffect: typeof useEffect = (effect, deps) => {
  const isFirstMount = useFirstMountState();

  useEffect(() => {
    if (!isFirstMount) {
      return effect();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);
};
